def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle related entities (e.g., country info)
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the monument as the main subject (look for "Monument" in subject name)
    main_subject = None
    for subj in subject_triples.keys():
        if "Monument" in subj or "Memorial" in subj or "Plack" in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect clauses for the main subject and related entities
    main_clauses: list[str] = []
    location_info: str = ""
    state_info: str = ""
    country_info: str = ""
    other_info: list[str] = []

    for subject, sub_triples in subject_triples.items():
        for triple in sub_triples:
            p = triple.predicate
            o = triple.object.strip('"')  # remove surrounding quotes if present

            # Map predicates to natural‑language fragments with better phrasing
            if subject == main_subject:
                if p == "category":
                    main_clauses.append(f"is a {o}")
                elif p in ("established", "foundingDate"):
                    main_clauses.append(f"was established on {o}")
                elif p == "inaugurationDate":
                    main_clauses.append(f"was inaugurated on {o}")
                elif p == "owner":
                    main_clauses.append(f"is owned by {o}")
                elif p == "owningOrganisation":
                    main_clauses.append(f"owned by {o}")
                elif p == "dedicatedTo":
                    main_clauses.append(f"is dedicated to {o}")
                elif p == "designer":
                    main_clauses.append(f"was designed by {o}")
                elif p == "material":
                    main_clauses.append(f"is made of {o}")
                elif p == "nativeName":
                    main_clauses.append(f'native name is "{o}"')
                elif p == "district":
                    main_clauses.append(f"in the district of {o}")
                elif p == "location":
                    location_info = o
                elif p == "municipality":
                    # Add to location chain instead
                    location_info = o if not location_info else f"{location_info}, {o}"
                elif p == "state":
                    state_info = o
                    # Don't add as main clause, handle in location phrase
                elif p == "country":
                    country_info = o
            else:
                # Handle related entity info (country, capital, etc.)
                # Only include info that's directly relevant to the monument
                if p == "capital":
                    # Store capital info but don't add to sentence unless monument-related
                    country_info = f"{subject} (capital: {o})"
                elif p == "nearestCity":
                    other_info.append(f"nearest city is {o}")
                elif p == "district":
                    other_info.append(f"located in {o}")
                # Skip country-level attributes like leader, currency, etc. as they're not monument-specific
                # This prevents adding unrelated information that violates the accuracy requirement

    # Build location phrase more naturally
    location_phrase_parts = []
    if location_info:
        location_phrase_parts.append(location_info)
    if state_info:
        location_phrase_parts.append(f"in {state_info}")
    # Only add country if it's not already implied by location_info
    if country_info and country_info not in location_info:
        location_phrase_parts.append(f"in {country_info}")

    location_text = ""
    if location_phrase_parts:
        # Join location parts naturally
        if len(location_phrase_parts) == 1:
            location_text = f"is located in {location_phrase_parts[0]}"
        else:
            # Combine location and state/country properly
            first_part = location_phrase_parts[0]
            remaining = location_phrase_parts[1:]
            if remaining:
                location_text = f"is located in {first_part}, {', '.join(remaining)}"
            else:
                location_text = f"is located in {first_part}"

    # Build the final sentence - only include monument-relevant information
    sentence_parts = [main_subject]

    # Add location first if present
    if location_text:
        sentence_parts.append(location_text)

    # Add main subject attributes
    if main_clauses:
        sentence_parts.extend(main_clauses)

    # Only add related entity info if it's directly about the monument
    # Don't include country-level attributes like leader unless monument-specific
    monument_related_info = [info for info in other_info if not any(x in info.lower() for x in ['leader', 'capital', 'currency', 'largest city'])]
    if monument_related_info:
        sentence_parts.append(f"with {', '.join(monument_related_info)}")

    # Combine into single sentence
    sentence = main_subject
    if location_text:
        sentence += f" {location_text}"
    if main_clauses:
        sentence += ", " + ", ".join(main_clauses)
    if monument_related_info:
        sentence += f", with {', '.join(monument_related_info)}"
    sentence += "."

    return sentence

